module top_module(
  input [7:0] A,
  input [7:0] B,
  input operation,
  input reset,
  output reg [7:0] C
);integer W;

  always @(*) begin
    if (reset) begin
      C <= 8'b0;
    end else if (operation) begin
      W = A - B;
      C <= W;
    end else begin
      W = A + B;
      C <= W;
    end
  end

endmodule
